        this.queue = new Array(maxSize);
        this.front = 0;
        this.rear = -1;
        this.currentSize = 0;
        this.taskSet = new Set();
    }

    isEmpty() {
        return this.currentSize === 0;
    }

    isFull() {
        return this.currentSize === this.maxSize;
    }

    enqueue(item) {
        if (this.isFull()) {
            console.log("Queue is full. Cannot enqueue.");
            return;
        }
        this.rear = (this.rear + 1) % this.maxSize; // Circular increment
        this.queue[this.rear] = item;
        this.currentSize++;
    }

    dequeue() {
        if (this.isEmpty()) {
            console.log("Queue is empty. Cannot dequeue.");
            return -1; // Return a sentinel value or throw an exception
        }
        const removedItem = this.queue[this.front];
        this.front = (this.front + 1) % this.maxSize; // Circular increment
        this.currentSize--;
        return removedItem;
    }

